sp_widget.client_script:
api.controller=function($scope, $interval, spUtil){
  /* widget controller */

  var c = this;

  // ── 1. Dynamic Time-of-Day Greeting ─────────────────────────────────────────
  function computeGreeting() {
    var hour = new Date().getHours();
    if (hour >= 5 && hour < 12)  return 'Good morning';
    if (hour >= 12 && hour < 17) return 'Good afternoon';
    if (hour >= 17 && hour < 21) return 'Good evening';
    return 'Welcome back';
  }

  // ── 2. First Name Extraction ─────────────────────────────────────────────────
  // c.firstName is populated by the server script below
  // Fallback gracefully if user data unavailable
  c.firstName = c.data.firstName || 'there';
  c.greetingText = computeGreeting();

  // ── 3. Greeting Subtext (context-aware) ─────────────────────────────────────
  var subtexts = [
    'Your health, managed digitally.',
    'Manage your prescriptions and requests below.',
    'All your pharmacy services, in one place.',
    'How can Pulse Pharmacy help you today?'
  ];
  c.greetingSubtext = subtexts[new Date().getDay() % subtexts.length];

  // ── 4. Live Clock ─────────────────────────────────────────────────────────────
  var DAYS   = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
  var MONTHS = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];

  function updateClock() {
    var now   = new Date();
    var h     = now.getHours();
    var m     = now.getMinutes();
    var ampm  = h >= 12 ? 'PM' : 'AM';
    var h12   = h % 12 || 12;

    c.currentTime = h12 + ':' + (m < 10 ? '0' : '') + m + ' ' + ampm;
    c.currentDate = MONTHS[now.getMonth()] + ' ' + now.getDate() + ', ' + now.getFullYear();
    c.dayOfWeek   = DAYS[now.getDay()];
  }

  updateClock();
  var clockInterval = $interval(updateClock, 30000); // refresh every 30 seconds

  // ── 5. Live RITM Stats ────────────────────────────────────────────────────────
  // Populated by server script; set loading state
  c.stats = {
    loaded:  false,
    pending: 0,
    total:   0
  };

  if (c.data.stats) {
    c.stats.pending = c.data.stats.pending || 0;
    c.stats.total   = c.data.stats.total   || 0;
    c.stats.loaded  = true;
  }

  // ── 6. Cleanup interval on scope destroy ─────────────────────────────────────
  $scope.$on('$destroy', function() {
    $interval.cancel(clockInterval);
  });
};/**
 * PP Hero Header — Client Controller
 * Handles: dynamic greeting, real-time clock, and live RITM stats
 */

sp_widget.css:
// ─── PP HERO HEADER WIDGET ───────────────────────────────────────────────────

.pp-hero {
  position: relative;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 36px 48px;
  background: linear-gradient(135deg, #0F172A 0%, #1E293B 55%, #1a1230 100%);
  border-radius: 0 0 12px 12px;
  overflow: hidden;
  min-height: 180px;
  margin-bottom: 8px;

  // ── Background Accents ─────────────────────────────────────
  &__bg-accent {
    position: absolute;
    inset: 0;
    pointer-events: none;
    z-index: 0;
  }

  &__accent-circle {
    position: absolute;
    border-radius: 50%;
    opacity: 0.06;
    background: #E60000;

    &--1 {
      width: 400px;
      height: 400px;
      top: -160px;
      right: -80px;
    }

    &--2 {
      width: 200px;
      height: 200px;
      bottom: -100px;
      right: 200px;
      opacity: 0.04;
    }
  }

  // ── Content (left side) ────────────────────────────────────
  &__content {
    position: relative;
    z-index: 1;
    display: flex;
    flex-direction: column;
    gap: 16px;
  }

  // ── Brand Wordmark ─────────────────────────────────────────
  &__brand {
    display: flex;
    align-items: center;
    gap: 10px;
  }

  &__brand-icon {
    display: flex;
    align-items: center;
    filter: drop-shadow(0 2px 4px rgba(230, 0, 0, 0.4));
  }

  &__brand-name {
    font-size: 16px;
    font-weight: 700;
    color: #FFFFFF;
    letter-spacing: -0.2px;
    font-family: 'Inter', sans-serif;
  }

  &__brand-badge {
    display: inline-flex;
    align-items: center;
    padding: 2px 8px;
    background: rgba(230, 0, 0, 0.18);
    border: 1px solid rgba(230, 0, 0, 0.35);
    border-radius: 100px;
    font-size: 10px;
    font-weight: 600;
    color: #FF6666;
    letter-spacing: 0.4px;
    text-transform: uppercase;
  }

  // ── Dynamic Greeting ───────────────────────────────────────
  &__greeting-text {
    margin: 0;
    font-size: 28px;
    font-weight: 700;
    color: #FFFFFF;
    letter-spacing: -0.5px;
    line-height: 1.2;
    font-family: 'Inter', sans-serif;
  }

  &__greeting-name {
    color: #FF6666;
    position: relative;

    &::after {
      content: '';
      position: absolute;
      bottom: -2px;
      left: 0;
      right: 0;
      height: 2px;
      background: linear-gradient(90deg, #E60000, transparent);
      border-radius: 2px;
    }
  }

  &__greeting-sub {
    margin: 4px 0 0;
    font-size: 14px;
    font-weight: 400;
    color: #94A3B8;
    letter-spacing: 0.1px;
  }

  // ── Stats Pills ────────────────────────────────────────────
  &__stats {
    display: flex;
    gap: 10px;
    flex-wrap: wrap;
    margin-top: 4px;
  }

  &__stat-pill {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    padding: 6px 14px;
    background: rgba(255, 255, 255, 0.07);
    border: 1px solid rgba(255, 255, 255, 0.12);
    border-radius: 100px;
    font-size: 13px;
    color: #CBD5E1;
    transition: background 0.2s ease;
    backdrop-filter: blur(4px);

    &--alert {
      background: rgba(230, 0, 0, 0.15);
      border-color: rgba(230, 0, 0, 0.3);
      color: #FCA5A5;

      .pp-hero__stat-icon { color: #E60000; }
    }
  }

  &__stat-icon {
    display: flex;
    align-items: center;
    color: #64748B;
  }

  &__stat-value {
    font-weight: 700;
    font-size: 14px;
    color: #FFFFFF;
  }

  &__stat-label {
    font-size: 12px;
    font-weight: 400;
  }

  // ── Clock (right side) ─────────────────────────────────────
  &__clock {
    position: relative;
    z-index: 1;
    text-align: right;
    display: flex;
    flex-direction: column;
    align-items: flex-end;
    gap: 4px;
    flex-shrink: 0;
  }

  &__clock-time {
    font-size: 42px;
    font-weight: 200;
    color: #FFFFFF;
    letter-spacing: -1px;
    font-family: 'Inter', sans-serif;
    line-height: 1;
  }

  &__clock-date {
    font-size: 13px;
    font-weight: 400;
    color: #94A3B8;
    letter-spacing: 0.5px;
  }

  &__clock-divider {
    width: 40px;
    height: 1px;
    background: linear-gradient(90deg, transparent, rgba(230, 0, 0, 0.5));
    margin: 4px 0;
  }

  &__clock-day {
    font-size: 11px;
    font-weight: 600;
    color: #64748B;
    text-transform: uppercase;
    letter-spacing: 1px;
  }

  &__clock-label {
    font-size: 11px;
    font-weight: 600;
    color: #E60000;
    text-transform: uppercase;
    letter-spacing: 1.5px;
  }

  // ── Responsive ─────────────────────────────────────────────
  @media (max-width: 768px) {
    flex-direction: column;
    align-items: flex-start;
    padding: 28px 24px;
    gap: 20px;

    &__clock {
      text-align: left;
      align-items: flex-start;

      &-time { font-size: 28px; }
    }

    &__greeting-text { font-size: 22px; }
  }
}

sp_widget.script:
/**
 * PP Hero Header — Server Script
 * Fetches: logged-in user's first name + RITM stats for pill display
 */
(function() {
  'use strict';

  data.firstName = '';
  data.stats     = { pending: 0, total: 0 };

  // ── 1. Resolve current user ──────────────────────────────────────────────────
  var userId = gs.getUserID();
  if (!userId) return; // anonymous user — gracefully exit

  var userGr = new GlideRecord('sys_user');
  if (userGr.get(userId)) {
    // Use first name; fall back to full name, then username
    data.firstName = userGr.first_name.toString()
      || userGr.name.toString().split(' ')[0]
      || userGr.user_name.toString();
  }

  // ── 2. Count this user's RITMs for the pharmacy catalog item ─────────────────
  // "Pending" = any stage that is not Completed or Rejected
  var CATALOG_ITEM_NAME = 'MedicineRequest'; // partial name match

  var totalGr = new GlideAggregate('sc_req_item');
  totalGr.addQuery('opened_by', userId);
  totalGr.addQuery('cat_item.name', 'CONTAINS', CATALOG_ITEM_NAME);
  totalGr.addAggregate('COUNT');
  totalGr.query();
  if (totalGr.next()) {
    data.stats.total = parseInt(totalGr.getAggregate('COUNT'), 10) || 0;
  }

  var pendingGr = new GlideAggregate('sc_req_item');
  pendingGr.addQuery('opened_by', userId);
  pendingGr.addQuery('cat_item.name', 'CONTAINS', CATALOG_ITEM_NAME);
  pendingGr.addQuery('stage', 'NOT IN', 'complete,rejected');
  pendingGr.addAggregate('COUNT');
  pendingGr.query();
  if (pendingGr.next()) {
    data.stats.pending = parseInt(pendingGr.getAggregate('COUNT'), 10) || 0;
  }

})();
